fr-gallery-core.desc:
Create src/lib/gallery.ts — plan gallery core: types, Pareto filtering, cardinal risk, candidate generation.

Exports:
  export interface TemplateParams {
    emitStrategy: "single-pass" | "two-stage" | "per-cluster"
    gateOrdering: "parallel" | "serial" | "cheapest-first"
    preExpansion: "none" | "from-history" | "from-spec-complexity"
    modelAllocation: "opus-all" | "opus-emit+haiku-fix" | "haiku-emit+opus-judge"
    convergence: "fixed-passes" | "until-clean" | "budget-capped"
  }

  export interface GalleryCandidate {
    id: string                    // "aggressive" | "corrective" | "staged" | "budget"
    label: string
    summary: string
    parameters: TemplateParams
    dag: Record<string, any>      // head.json-compatible DAGSpec
    estimates: {
      nodes: number
      maxExpansion: number
      wallClockMinutes: number
      costUSD: number
      risk: number                // cardinal: 0.0–1.0 = 1 - (historicalSuccessRate * gateConvergenceRate)
    }
    gateProfile: { deterministic: number; intent: number; runtime: number }
    historySignal?: {
      priorFailureClasses: string[]
      preExpanded: string[]
      templateSuccessRate: number
    }
  }

  export function computeRisk(historicalSuccessRate: number, gateConvergenceRate: number): number
    // risk = 1 - (historicalSuccessRate * gateConvergenceRate)
    // No history → both rates default to 0 → risk = 1.0

  export function paretoFilter(candidates: GalleryCandidate[]): GalleryCandidate[]
    // Prune dominated candidates. A is dominated by B if:
    //   B.estimates.costUSD <= A.estimates.costUSD AND
    //   B.estimates.wallClockMinutes <= A.estimates.wallClockMinutes AND
    //   B.estimates.risk <= A.estimates.risk AND at least one strictly less.
    // Target: 3-4 survivors.
    // On cold start (all risk=1.0): conservative template always survives.

  export function generateCandidates(specSource: string, historyDir?: string): GalleryCandidate[]
    // Generate all template combinations, score with computeRisk, run paretoFilter.
    // historyDir = path to .roadmap/evaluations/ (optional, skipped if missing)

No Anthropic API calls. This is pure data generation + filtering.

fr-emit-gallery-core.desc:
Create src/lib/emit-gallery.ts — multi-candidate code generation: parallel execution, gating, scorecard.

Exports:
  export interface CandidateResult {
    id: string
    strategy: string
    files: Record<string, string>  // path → content
    deterministic: {
      tsc: { pass: boolean; errors?: string[] }
      vitest: { pass: boolean; passed: number; failed: number; coverage: number }
      build: { pass: boolean; outputs?: string[] }
    }
    intent: Array<{ statement: string; pass: boolean; confidence: number; reasoning: string; evidence: string[] }>
    summary: { loc: number; fileCount: number; deterministicPass: boolean; intentScore: string; estimatedCost: number }
  }

  export type FileToIntents = Record<string, string[]>

  export function buildFileToIntents(validateRules: ValidationRule[]): FileToIntents
    // Invert intent rule contextPaths: statement→files → files→statements
    // Rule with no contextPaths: skip (requires explicit context for blend substitutability)

  export interface ConvergenceConfig {
    maxFixPasses: number          // per gate, default 3
    escalateAfter: "all-candidates-fail" | "fix-pass-stall"
    escalateTo: "human" | "opus-review"
  }

  export interface GalleryFailure {
    unreachable: string           // intent statement that no candidate satisfied
    bestConfidence: number
    threshold: number
    candidates: number
    diagnosis: string             // e.g. "all candidates used @media prefers-color-scheme"
  }

  export interface GalleryRunResult {
    candidates: CandidateResult[]
    survivors: CandidateResult[]  // passed deterministic gates
    intentSurvivors: CandidateResult[]  // also passed intent gates
    failures: GalleryFailure[]    // unreachable intents
    scorecard: string             // ASCII table for CLI rendering
  }

  export async function runGallery(opts: {
    nodeSpec: EmitGalleryNodeSpec,
    strategies: StrategySpec[],
    workDir: string,              // .roadmap/gallery/
    convergence?: ConvergenceConfig,
  }): Promise<GalleryRunResult>
    // Generates candidates in parallel (Promise.all), gates each, builds scorecard.
    // Does NOT make real LLM calls — stubs candidates as empty file sets for now.
    // Real LLM dispatch is a future FR. This FR establishes the pipeline + types.

Import EmitGalleryNodeSpec from src/protocol.ts.
Import StrategySpec from src/lib/strategies/index.ts.
Import ValidationRule from src/protocol.ts.

Key invariant: gallery is diversity not retry.
  If all candidates fail the same intent → GalleryFailure, not loop.
  maxFixPasses applies per gate after selection, not to generation.
